// ---------- team prep: pick XI (keeper + >=5 bowlers + best bats), order by mpos ----------
function pickXI(team){
  // a set XI (NPC ordersMap or the user's saved orders) wins outright,
  // if it names 11 real players including five bowlers
  try{
    let O=null;
    if(typeof M!=='undefined'&&M&&M.ordersMap&&M.ordersMap[team.name])O=M.ordersMap[team.name];
    else{try{if(typeof App!=='undefined'&&App.orders&&userTeam()===team)O=App.orders}catch(eU){}}
    const xiN=O&&O.xi;
    if(xiN&&xiN.length===11){
      const by={};(team.players||[]).forEach(p=>{by[p.name]=p});
      const picked=[],seen={};
      xiN.forEach(nm=>{if(by[nm]&&!seen[nm]){seen[nm]=1;picked.push(by[nm])}});
      if(picked.length===11&&picked.filter(p=>p.bowlType).length>=5)return picked;
    }
  }catch(e){}
  const P=team.players.slice();
  const kps=P.filter(p=>p.keeper).sort((a,b)=>b.bat-a.bat);
  const keeper=kps[0]||P.sort((a,b)=>b.bat-a.bat)[0];
  const bowlers=P.filter(p=>p.bowlType&&p.key!==keeper).sort((a,b)=>(b.threat+b.control)-(a.threat+a.control));
  const five=bowlers.slice(0,5);
  const chosen=new Set([keeper.name,...five.map(b=>b.name)]);
  const rest=P.filter(p=>!chosen.has(p.name)).sort((a,b)=>b.bat-a.bat);
  for(const r of rest){if(chosen.size>=11)break;chosen.add(r.name)}
  const xi=P.filter(p=>chosen.has(p.name));
  xi.sort((a,b)=>(a.mpos-b.mpos)||(b.bat-a.bat));
  return xi;
}
