function endInnings(){
  const inn=M.innings[M.inns];
  if(M.inns===0){
    for(const k in M.fat)M.fat[k]*=0.5;M.fatWarned={};
    M.target=inn.runs+1;M.inns=1;
    const bat2=(inn.batTeam===M.user.name)?M.ai:M.user;
    const bowl2=(bat2===M.user)?M.ai:M.user;
    M.innings[1]=mkInns(bat2,bowl2);
    M.log.unshift({no:'',out:'-',txt:`Innings break. ${inn.batTeam} ${inn.runs}/${inn.wkts}. Target ${M.target}.`,d:null,inn:0,mile:true});
    UI.intent=0;UI.field='bal';setPills();
  }else{M.done=true;banner()}
}
function banner(){
  const a=M.innings[0],b=M.innings[1];let res,marg;
  if(b.runs>=M.target){res=b.batTeam;marg=`by ${10-b.wkts} wickets (${foBallCap()-b.legal} balls left)`}
  else if(b.runs===M.target-1){res=null;marg='Match tied'}
  else{res=a.batTeam;marg=`by ${M.target-1-b.runs} runs`}
  // MoM: top runs+2*wkts... simple
  let best=null,bv=-1;
  for(const inn of M.innings){for(const s of inn.bat){const v=s.r;if(v>bv){bv=v;best=s.p.name+' '+s.r}}
    for(const k in inn.bowlers){const r=inn.bowlers[k];const v=r.w*35;if(v>bv){bv=v;best=k+' '+r.w+'w'}}}
  M.result={winner:res,text:(res?res+' win '+marg:'Match tied'),mom:best};
  if(typeof onMatchEnd==='function')onMatchEnd();
}
