const TALTIPS={fastStarter:'Passive - halves the new-batter settling penalty',anchor:'Triggered - harder to dismiss while the innings is under control',finisher:'Triggered - extra boundary power in overs 41-50',sixMachine:'Triggered - bigger six odds when attacking/launching',spinKiller:'Passive - plays spin notably better',paceHunter:'Passive - plays pace notably better',busyRunner:'Passive - more singles and twos',newBallSpecialist:'Triggered - extra wicket threat while the ball is new',deathSpecialist:'Triggered - better containment at the death',partnershipBreaker:'Triggered - extra threat once a stand passes 50',bouncer:'Triggered - hurries batters weak against pace',miser:'Passive - more dot balls',goldenArm:'Triggered - extra bite in the first two overs of a spell',mysteryBall:'Triggered - dangerous to unfamiliar batters',lightningHands:'Passive - sharper keeping, keeper catches and stumpings',safeHands:'Passive - drops fewer catches',rocketArm:'Passive - raises run-out pressure and gets involved in more run-outs'};
