// live effective-strength heuristics - mirror the engine's log-odds terms, mapped to a 0-100 display scale
function effBat(bat,bowl,ctx){
  const tc=typeClass(bowl.bowlType||'fastMedium');
  let v=bat.bat+CAL.matchup*(((tc==='pace'?(bat.vsPace??50):(bat.vsSpin??50)))-50);
  v-=16*Math.exp(-(ctx.faced??30)/CAL.setness_scale);
  v+=((bat.formIx??3)-3)*1.2-(bat.fatigue==='tired'?2:0);
  const T=bat.talents||[];
  if(T.includes('fastStarter'))v+=8*Math.exp(-(ctx.faced??30)/CAL.setness_scale);
  if(T.includes('finisher')&&(ctx.over??20)>=40)v+=4;
  if(T.includes('anchor')&&(ctx.rrDef??0)<=0)v+=3;
  if((ctx.pitch==='flat'))v+=4;if(ctx.pitch==='twoPaced'||ctx.pitch==='cracked')v-=4;
  if(ctx.weather==='hot')v+=2;if(ctx.weather==='drizzle')v-=2;
  return Math.max(5,Math.min(97,Math.round(v)));
}
function effBowl(bat,bowl,ctx){
  const tc=typeClass(bowl.bowlType||'fastMedium');
  const nb=Math.exp(-(ctx.over??20)/8),grip=1/(1+Math.exp(-((ctx.over??20)-25)/8));
  let v=0.55*(bowl.threat||40)+0.45*(bowl.control||40);
  v+=((bowl.formIx??3)-3)*1.2-(bowl.fatigue==='tired'?2:0);
  if(tc==='pace'){v+=14*nb*(ctx.pitch==='green'?1.5:1);if(ctx.weather==='overcast')v+=4;if(ctx.weather==='humid')v+=5*nb}
  else{v+=14*grip*(ctx.pitch==='dry'?1.6:1)-8*nb;if(ctx.weather==='dew later'&&ctx.chase)v-=4}
  if(ctx.pitch==='cracked')v+=4;if(ctx.pitch==='twoPaced')v+=3;
  const T=bowl.talents||[];
  if(T.includes('newBallSpecialist'))v+=8*nb;
  if(T.includes('deathSpecialist')&&(ctx.over??20)>=40)v+=5;
  if(T.includes('partnershipBreaker')&&(ctx.pship??0)>=50)v+=5;
  return Math.max(5,Math.min(97,Math.round(v)));
}
