function groundPitch(g){const t=GD.teams.find(x=>x.ground===g);return (t&&t.homePitch)||GPITCH[g]||'balanced'}
function econInit(){
  if(App.fin)return;
  App.fin={bank:500000,ledger:[]};
  App.seasonNo=1;App.history=[];
  App.market={listed:[],myBids:{},round:-1};
  App.cup={stage:0,alive:null,results:[],out:false};
  for(const t of GD.teams){t.acadY=t.acadY||2;t.acadS=t.acadS||2;t.seats=t.seats||9000;
    t.supporters=t.supporters||2600;t.mood=t.mood??3;t.homePitch=t.homePitch||groundPitch(t.ground);t.bank=t.bank||500000;}
}
function playerValue(p){return Math.max(8000,Math.round(p.wage*34+(p.rating-3200)*18))}
function roleClass(p){return p.bowlType?(p.role==='allRounder'?'ar':'bowl'):(p.role==='wicketkeeper'?'wk':'bat')}
function clubNeed(t,rc){ // weaker area = bigger need multiplier
  const xi=pickXI(t);
  const bat=xi.slice(0,7).reduce((a,p)=>a+aggBat(p),0)/7;
  const bw=xi.filter(p=>p.bowlType);const bowl=bw.reduce((a,p)=>a+aggBowl(p),0)/Math.max(1,bw.length);
  if(rc==='bat'||rc==='wk')return bat<bowl?1.25:0.9;
  if(rc==='bowl')return bowl<bat?1.25:0.9;
  return 1.05;}
function genListings(){
  econInit();const S=App.season;if(App.market.round===S.round)return;
  App.market.round=S.round;
  const keep=App.market.listed.filter(l=>l.seller===userTeam().name); // user listings persist till resolved
  App.market.listed=keep;
  let h=(S.round*2654435761)>>>0;const rnd=()=>((h=(h*1103515245+12345)>>>0)/4294967296);
  const pool=[];
  for(let i=0;i<GD.teams.length;i++){if(i===App.teamIx)continue;
    for(const p of GD.teams[i].players)if(p.rating>3100)pool.push({p,club:i});}
  pool.sort(()=>rnd()-0.5);
  for(const c of pool.slice(0,8)){
    App.market.listed.push({name:c.p.name,seller:GD.teams[c.club].name,base:playerValue(c.p),deadline:S.round});}
}
function listOwnPlayer(nm,ask){econInit();
  if(App.market.listed.some(l=>l.name===nm))return;
  App.market.listed.push({name:nm,seller:userTeam().name,base:Math.max(1000,ask|0),deadline:App.season.round});
  pgMarket();}
function resolveMarket(){
  econInit();const S=App.season;const me=userTeam();const news=[];
  let h=(S.round*40503+7)>>>0;const rnd=()=>((h=(h*1103515245+12345)>>>0)/4294967296);
  for(const l of App.market.listed){
    const fp=findPlayer(l.name);if(!fp){continue}
    const rc=roleClass(fp.p);
    let best=null;
    for(let i=0;i<GD.teams.length;i++){
      const t=GD.teams[i];if(t.name===l.seller)continue;
      if(t.players.length>=18)continue;
      const isMe=(i===App.teamIx);
      if(isMe){const my=App.market.myBids[l.name]|0;
        if(my>=l.base&&my<=App.fin.bank&&(!best||my>best.amt))best={t,amt:my,me:true};
        continue;}
      const val=playerValue(fp.p)*clubNeed(t,rc)*(0.8+0.45*rnd());
      const amt=Math.round(val/500)*500;
      if(amt>=l.base&&amt<=t.bank*0.4&&(!best||amt>best.amt))best={t,amt,me:false};
    }
    if(best){
      const from=GD.teams.find(t=>t.name===l.seller);
      const ix=from.players.findIndex(p=>p.name===l.name);
      const[pl]=from.players.splice(ix,1);
      best.t.players.push(pl);
      if(best.me)ledger('Bought '+pl.name,-best.amt);else if(from===me)ledger('Sold '+pl.name,+best.amt);
      if(!best.me)best.t.bank-=best.amt;
      if(from!==me)from.bank+=best.amt;
      news.push(pl.name+' → '+best.t.name+' for $'+best.amt.toLocaleString());
    }
  }
  App.market.listed=[];App.market.myBids={};
  if(news.length)App.news=(news.map(n=>'TRANSFER: '+n)).concat(App.news||[]).slice(0,12);
}
// ---- Senior One Day Cup: prelims R3, QF R7, SF R12, Final R16 (after those league rounds complete) ----
const CUPROUNDS={3:'Preliminaries',7:'Quarter-finals',12:'Semi-finals',16:'Final'};
function cupSeeds(){ // league position order at first cup round
  const rows=leagueRows();const ix=nm=>GD.teams.findIndex(t=>t.name===nm);
  return rows.map(r=>ix(r.nm)).filter(i=>i>=0);
}
function cupTick(){ // called at completeRound AFTER league round increments? we call before ++ with S.round = just-played round
  econInit();const S=App.season;const C=App.cup;const rd=S.round+1; // human-numbered round just completed
  if(!CUPROUNDS[rd])return;
  if(C.alive===null){const seeds=cupSeeds();C.alive=seeds.length===10?seeds:GD.teams.map((_,i)=>i);}
  let pairs=[];
  if(rd===3){ // seeds 7-10 play in; 1-6 byes
    pairs=[[C.alive[6],C.alive[9]],[C.alive[7],C.alive[8]]];
    C.next=C.alive.slice(0,6);
  }else{
    const a=C.alive;pairs=[];for(let i=0;i<a.length/2;i++)pairs.push([a[i],a[a.length-1-i]]);
    C.next=[];
  }
  const winners=[];
  for(let i=0;i<pairs.length;i++){const f=pairs[i];
    const home=GD.teams[f[0]];
    const isUser=(f[0]===App.teamIx||f[1]===App.teamIx);
    const meta={home:home.name,away:GD.teams[f[1]].name,ground:home.ground,pitch:groundPitch(home.ground),
      weather:WXLIST[(rd*11+f[0])%WXLIST.length],seed:7700+rd*20+f[0],date:simDate(),comp:'cup',round:S.round,isUser:false};
    simBackground(f[0],f[1],meta);
    const r=App.results[App.results.length-1];
    const wIx=GD.teams.findIndex(t=>t.name===r.result.winner);
    winners.push(wIx);
    App.news=(['CUP ('+CUPROUNDS[rd]+'): '+r.result.text]).concat(App.news||[]).slice(0,12);
    if(isUser&&wIx!==App.teamIx)C.out=true;
  }
  C.alive=(C.next||[]).concat(winners);
  if(rd===16){C.champion=GD.teams[C.alive[0]].name;
    if(C.alive[0]===App.teamIx)ledger('Cup winners prize',120000);
    App.news=(['CUP FINAL: '+C.champion+' lift the Senior One Day Cup!']).concat(App.news||[]).slice(0,12);}
  C.results.push({rd,stage:CUPROUNDS[rd]});
}
