function ledger(label,amt){App.fin.bank+=amt;App.fin.ledger.unshift({wk:'S'+App.seasonNo+' R'+((App.season?App.season.round:0)+1),label,amt});if(App.fin.ledger.length>200)App.fin.ledger.pop()}
