const S=p=>p.skills||{};
const aggBat=p=>Math.round(.25*S(p).vsPace+.25*S(p).vsSpin+.2*S(p).rotation+.15*S(p).temperament+.15*S(p).power);
const aggBowl=p=>p.bowlType?Math.round((S(p).wicket+S(p).economy+S(p).discipline+S(p).moveTurn+S(p).variation+S(p).stamina)/6):Math.round(S(p).wicket*0.3||5);
const aggKeep=p=>p.keeper?Math.round((S(p).keeping+S(p).stumping+S(p).catching)/3):Math.min(15,Math.round(S(p).keeping||8));
const aggTech=p=>Math.round((S(p).vsPace+S(p).vsSpin+S(p).temperament)/3);
const aggEnd=p=>p.bowlType?S(p).stamina:Math.round(S(p).temperament*0.9);
const aggField=p=>Math.round((S(p).fielding+S(p).catching)/2);
