  `<div class="ctlrow"><span>Club:</span><select onchange="playersClub=+this.value;pgPlayers()">${GD.teams.map((x,i)=>`<option value="${i}" ${i===playersClub?'selected':''}>${esc(x.name)}</option>`).join('')}</select></div>`+
  gridTable(sortPlayers(t.players));
