    <div class="panel"><h4>Fielding (ct/st/ro)</h4><div class="pad"><table>${FS.map(x=>`<tr><td>${esc(x.nm)}</td><td class="n">${x.ct}/${x.st}/${x.ro}</td></tr>`).join('')||'<tr><td class="small">-</td></tr>'}</table></div></div>
