function store(k,v){try{if(v===undefined)return localStorage.getItem(k);localStorage.setItem(k,v);return v}catch(e){window.__mem=window.__mem||{};if(v===undefined)return window.__mem[k];window.__mem[k]=v;return v}}
function foResetGame(){
  // #8 Robust reset: explicitly remove every fo_* key (clear() can silently fail in restricted
  // storage, which used to leave the old founded squad behind), wipe in-memory state, then reload.
  try{
    const keys=[];for(let i=0;i<localStorage.length;i++){const k=localStorage.key(i);if(k&&(k.indexOf('fo_')===0||k.indexOf('fol_')===0))keys.push(k);}
    keys.forEach(k=>{try{localStorage.removeItem(k)}catch(e){}});
    try{localStorage.clear()}catch(e){}
  }catch(e){}
  try{window.__mem={};}catch(e){}
  try{App.founder=null;App.season=null;App.results=[];}catch(e){}
  location.hash='#/welcome';location.reload();
}
