// ---------- Founder mode: build your own club from a draft pool ----------
function hashStr(s){let h=2166136261>>>0;for(let i=0;i<s.length;i++){h^=s.charCodeAt(i);h=Math.imul(h,16777619)>>>0}return h>>>0}
function cap(s){return s.charAt(0).toUpperCase()+s.slice(1)}
function genDraftPool(seedStr){
  let h=hashStr(seedStr||'club')>>>0;const rnd=()=>((h=(h*1103515245+12345)>>>0)/4294967296);
  const NAT=['Australia','India','Pakistan','Sri Lanka','New Zealand','South Africa','England','Netherlands','West Indies','Afghanistan','Ireland','Zimbabwe'];
  const EXPW=['atrocious','dreadful','poor','ordinary','average','reasonable','capable','reliable','accomplished','expert','spectacular','elite'];
  const used=new Set();
  const g=(m,s)=>Math.max(5,Math.min(96,Math.round(m+s*(rnd()+rnd()+rnd()-1.5))));
  // ---- squad composition: 42 players, role-balanced, all-rounders deliberately capped ----
  // ---- SCARCITY-BANDED DRAFT: few elites, hard cliffs, long journeyman tail ----
  // Tier multipliers with GAPS between bands so missing a tier is a real loss, not one rung.
  const TIER={franchise:1.62,star:1.30,solid:0.98,journeyman:0.70,project:0.52};
  // Per-role tier budgets. Deliberately scarce at the top: in a 4-founder league someone
  // WILL be frozen out of every premium position. Batting is the deepest; keepers the thinnest.
  const roleBands={
    bat:   ['franchise','franchise','star','star','star','solid','solid','solid','solid','journeyman','journeyman','journeyman','project','project'],
    wk:    ['star','solid','journeyman','journeyman','project'],                 // ONE good keeper. That's it.
    ar:    ['star','solid','solid','journeyman','journeyman','project'],         // no franchise all-rounders - specialists define the top
    pace:  ['franchise','star','star','solid','solid','journeyman','journeyman','project','project'],
    spin:  ['franchise','star','solid','solid','journeyman','journeyman','project','project','project']
  };
  const plan=[];
  const pushBand=(role,tiers)=>tiers.forEach(t=>plan.push({role,tier:t}));
  // batting: mix of openers/top/middle across the 14 bat slots
  const batRoles=['opener','opener','topOrderBat','topOrderBat','topOrderBat','middleOrderBat','middleOrderBat','middleOrderBat','middleOrderBat','opener','topOrderBat','middleOrderBat','middleOrderBat','opener'];
  roleBands.bat.forEach((t,i)=>plan.push({role:batRoles[i%batRoles.length],tier:t}));
  pushBand('wicketkeeper',roleBands.wk);
  pushBand('allRounder',roleBands.ar);
  // Scarcity ladder (same tier multiset as before, but bowl types are no longer evenly cycled):
  // PACE (9): exactly ONE genuine fast bowler per pool - and he's the franchise pace asset.
  //   Fast > FastMedium > Medium in rarity: 1 fast, 3 fast-medium, 5 medium.
  // SPIN (9): wrist spin is the scarce, top-heavy craft: 3 wrist (franchise/star/flier), 6 finger.
  [ {r:'seamFast',t:'franchise'},
    {r:'seamFastMedium',t:'star'},{r:'seamFastMedium',t:'solid'},{r:'seamFastMedium',t:'journeyman'},
    {r:'seamMedium',t:'star'},{r:'seamMedium',t:'solid'},{r:'seamMedium',t:'journeyman'},{r:'seamMedium',t:'project'},{r:'seamMedium',t:'project'}
  ].forEach(s=>plan.push({role:s.r,tier:s.t}));
  [ {r:'wristSpin',t:'franchise'},{r:'wristSpin',t:'star'},{r:'wristSpin',t:'journeyman'},
    {r:'fingerSpin',t:'solid'},{r:'fingerSpin',t:'solid'},{r:'fingerSpin',t:'journeyman'},{r:'fingerSpin',t:'project'},{r:'fingerSpin',t:'project'},{r:'fingerSpin',t:'project'}
  ].forEach(s=>plan.push({role:s.r,tier:s.t}));
  const pool=[];
  for(const slot of plan){
    const role=slot.role;
    const isB=['seamFast','seamFastMedium','seamMedium','wristSpin','fingerSpin'].includes(role);
    const isWK=role==='wicketkeeper';
    const isAR=role==='allRounder';
    const isBat=!isB&&!isWK&&!isAR;
    // quality q in [0,1] from the tier band (+ per-player noise), then AGE x QUALITY skills.
    const tierMult=(TIER[slot.tier]||0.9);
    const q=Math.max(0.05,Math.min(0.99,(tierMult-0.45)/1.25+(rnd()-0.5)*0.16));
    // Age: 18 (floor) .. 30 (oldest), weighted toward mid-20s so peak-age players exist.
    const age=Math.max(18,Math.min(30,18+Math.floor((rnd()+rnd())*6.5)));
    const skills=foGenSkills(role,q,age,rnd);
    const exp=foGenExp(age,q,rnd);
    const nat=NAT[Math.floor(rnd()*NAT.length)];
    const nm=natName(nat,rnd,used);used.add(nm);
    const p={name:nm,age,nat,hand:rnd()<0.72?'R':'L',role,
      bowlTypeFull:(isB?role:(isAR?(rnd()<0.5?'seamMedium':'fingerSpin'):'none')),keeper:isWK,
      exp,expWord:foExpWordOf(exp),capt:g(45,16),formIx:3,fatigue:'rested',skills,talents:[]};
    // talents: specialists get specialty-fitting ones; capped so they read as flavor not noise
    const elig=Object.keys(TALN).filter(t=>{
      if(t==='lightningHands')return isWK;
      if(t==='bouncer')return ['seamFast','seamFastMedium'].includes(p.bowlTypeFull);
      if(t==='mysteryBall')return ['wristSpin','fingerSpin'].includes(p.bowlTypeFull);
      if(['newBallSpecialist','deathSpecialist','miser','goldenArm','partnershipBreaker'].includes(t))return isB||isAR;
      // batting talents gated to the batting SITUATION they fit
      if(t==='fastStarter')return role==='opener';                          // new-ball aggressor
      if(t==='anchor')return role==='opener'||role==='topOrderBat';         // builds the innings
      if(t==='finisher')return role==='middleOrderBat'||isAR;               // death hitter, never an opener
      if(t==='sixMachine')return role==='middleOrderBat'||isAR||isWK;       // lower-order power
      if(t==='busyRunner')return isBat||isAR||isWK;
      if(t==='spinKiller'||t==='paceHunter')return isBat||isAR||isWK;
      return true});
    const nT=tierMult>1.1?(rnd()<0.6?2:1):(rnd()<0.5?1:0);
    for(let k=0;k<nT&&elig.length;k++){const t=elig.splice(Math.floor(rnd()*elig.length),1)[0];p.talents.push(t)}
    jsDerive(p);
    p.wage=Math.max(700,Math.round((p.rating*0.045+p.talents.length*120)/10)*10);
    pool.push(p);
  }
  // ---- PRICING: 5-8 superstars affordable, the rest fillers, and no squad can be elite everywhere ----
  const rcls=p=>p.keeper?'wk':(p.role==='allRounder'?'ar':(p.bowlTypeFull!=='none'?'bowl':'bat'));
  const specialty=p=>{
    const bat=aggBat(p),bowl=p.bowlType?aggBowl(p):0,keep=p.skills.keeping;
    const cls=rcls(p);
    if(cls==='bat')return bat+0.15*p.skills.power;
    if(cls==='bowl')return bowl+0.10*bat;
    if(cls==='wk')return 0.62*keep+0.55*bat;
    return 0.9*Math.max(bat,bowl)+0.35*Math.min(bat,bowl)+3;
  };
  pool.forEach(p=>{p._raw=specialty(p);p._cls=rcls(p)});
  // within-role percentile (cross-role normalized), then map to three price bands with gaps:
  // superstar $105k-$160k · mid $38k-$62k · filler $14k-$24k
  const groups={};for(const p of pool)(groups[p._cls]=groups[p._cls]||[]).push(p);
  for(const cls in groups){
    const arr=groups[cls].sort((a,b)=>a._raw-b._raw);const m=arr.length;
    arr.forEach((p,i)=>{p._pct=m>1?i/(m-1):0.5});
  }
  pool.forEach(p=>{
    let band, t;
    const pct=p._pct*(p._cls==='ar'?0.92:1);
    if(pct>=0.72){band='star';t=(pct-0.72)/0.28}
    else if(pct>=0.42){band='mid';t=(pct-0.42)/0.30}
    else{band='filler';t=pct/0.42}
    p.band=band;
    const f=band==='star'?105000+t*55000:band==='mid'?38000+t*24000:14000+t*10000;
    // Scarcity premium: genuine pace is the rarest commodity in the game, wrist spin the rarest spin.
    // You pay for what you can't find elsewhere - over and above raw skill.
    const scar=p.bowlTypeFull==='seamFast'?1.35:(p.bowlTypeFull==='wristSpin'?1.15:1);
    p.fee=Math.round(f*scar/1000)*1000;
    p.wage=Math.max(700,Math.round((p.rating*0.045*scar+(p.talents?p.talents.length:0)*120)/10)*10);
  });
  return pool;
}
