    if(role==='bowl')list=list.filter(p=>p.bowlTypeFull&&p.bowlTypeFull!=='none'&&p.role!=='allRounder');
    if(role==='ar')list=list.filter(p=>p.role==='allRounder'); if(role==='wk')list=list.filter(p=>p.keeper);
