    if(role==='cheap')list=list.filter(p=>p.fee<=75000); if(role==='stars')list=list.filter(p=>p.rating>=3600||p.fee>=130000); if(role==='upside')list=list.filter(p=>p.age<=24||potentialFor(p)==='Star'||potentialFor(p)==='High');
