    const bowl=F.picked.filter(p=>p.bowlTypeFull&&p.bowlTypeFull!=='none').length, wk=F.picked.filter(p=>p.keeper).length, ar=F.picked.filter(p=>p.role==='allRounder').length, youth=F.picked.filter(p=>p.age<=22).length;
