    const warnings=[]; if(F.picked.length<11)warnings.push(`${F.picked.length}/11 players`); if(wk<1)warnings.push('No keeper'); if(bowl<5)warnings.push(`Only ${bowl}/5 bowling options`); if(tailRisk)warnings.push('Tail looks long'); if(death<1)warnings.push('No death bowler'); if(spin<1)warnings.push('No spin option'); if(pace<1)warnings.push('No pace option'); if(F.picked.length<=12)warnings.push('Thin squad'); if(left<25000)warnings.push('Tiny budget remaining');
    const positives=[]; if(batTop>=4)positives.push('Strong top order'); if(spin>=2)positives.push('Excellent spin attack'); if(F.picked.length>=14&&!tailRisk)positives.push('Deep batting'); if(youth>=3)positives.push('Good youth upside'); if(pace>=3)positives.push('Pace depth');
