function foIsTalentText(txt){return /SIX MACHINE|Finisher|PARTNERSHIP BREAKER|New Ball Specialist|Golden Arm|Mystery Ball|Bouncer|Lightning Hands|Rocket Arm|Safe Hands|Miser|Spin Killer|Pace Hunter|Fast Starter|Anchor|death specialist/i.test(txt||'')}
function foCommPass(L,filter){
  filter=filter||'all'; if(filter==='all')return true;
  const txt=L.txt||'';
  if(filter==='wickets')return isWkt(L.out)||/WICKET|out for|Partnership ends/i.test(txt);
  if(filter==='boundaries')return L.out==='4'||L.out==='6'||/FOUR|SIX/i.test(txt);
  if(filter==='overs')return L.mile||/End of over|DRINKS|Innings break|CHASE BEGINS|PLAY BEGINS/i.test(txt);
  if(filter==='fielding')return L.out==='wC'||L.out==='wRO'||L.out==='wST'||/DROPPED|Misfield|fumbles|Brilliant stop|diving stop|phenomenal stop|attacks the ball|Stumping chance missed|Rocket Arm|Lightning Hands|run out|caught (behind|at|by)|takes (a|the|it|his).{0,24}catch|saves two|cuts it off/i.test(txt);
  if(filter==='talents')return foIsTalentText(txt);
  if(filter==='highlights')return L.mile||isWkt(L.out)||L.out==='4'||L.out==='6'||foIsTalentText(txt)||/DROPPED|FIFTY|HUNDRED/i.test(txt);
  return true;
}
function foRenderCommentText(txt){
  let h=esc(txt||'');
  const names=['SIX MACHINE','PARTNERSHIP BREAKER','New Ball Specialist','Golden Arm','Mystery Ball','Bouncer','Finisher','Lightning Hands','Rocket Arm','Safe Hands','Miser','Spin Killer','Pace Hunter','Fast Starter','Anchor','death specialist'];
  for(const n of names){const re=new RegExp('('+n.replace(/[.*+?^${}()|[\]\\]/g,'\\$&')+')','ig');h=h.replace(re,'<span class="talent-hit">$1</span>')}
  return h;
}
function foFilterSelect(scope){
  const key=scope==='saved'?'_savedCommFilter':'commFilter';
  const cur=(scope==='saved'?(App._savedCommFilter||'all'):(UI.commFilter||'all'));
  return `<span class="comm-filter"><span>Display</span><select onchange="${scope==='saved'?'App._savedCommFilter':'UI.commFilter'}=this.value;${scope==='saved'?'route()':'renderMatch()'}">
    ${[['all','All commentary'],['highlights','Highlights'],['wickets','Wickets'],['boundaries','Boundaries'],['fielding','Fielding'],['overs','Over summaries'],['talents','Ability triggers']].map(([v,l])=>`<option value="${v}" ${cur===v?'selected':''}>${l}</option>`).join('')}
  </select></span>`;
}
function foCommentRows(log,filter,limit){
  return (log||[]).filter(L=>foCommPass(L,filter)).slice(0,limit||90).map(L=>{
    const cls=L.out==='4'?'four':L.out==='6'?'six':isWkt(L.out)?'W':'';
    const bg=isWkt(L.out)?'background:#fbe9e7;':(L.out==='6'?'background:#fdf6df;':(L.out==='4'?'background:#eef4fa;':''));
    const ability=foIsTalentText(L.txt)?' ability-row':'';
    return `<div class="bl ${L.mile?'mile':''}${ability}" style="${bg}"><b class="${cls}">${esc(L.no||'')}</b> ${foRenderCommentText(L.txt)}</div>`;
  }).join('')||'<span class="small">No commentary matches this filter.</span>';
}
function foTinyScorecardForInnings(inn){
  if(!inn)return '<div class="small">No innings yet.</div>';
  const bat=inn.bat.filter(b=>b.b>0||b.out||(!b.out&&(b===inn.bat[inn.striker]||b===inn.bat[inn.nonstriker]))).map(b=>`<tr><td>${playerLink(b.p)}${!b.out?' *':''}</td><td class="small">${esc(b.out||'not out')}</td><td class="n"><b>${b.r}</b></td><td class="n">${b.b}</td><td class="n">${b.f4}</td><td class="n">${b.f6}</td><td class="n">${b.b?(100*b.r/b.b).toFixed(1):'-'}</td></tr>`).join('');
  const bowl=Object.values(inn.bowlers||{}).map(r=>`<tr><td>${playerLink(r.p)}</td><td class="n">${Math.floor(r.b/6)}.${r.b%6}</td><td class="n">${r.r}</td><td class="n"><b>${r.w}</b></td><td class="n">${r.b?(r.r/(r.b/6)).toFixed(2):'-'}</td></tr>`).join('')||'<tr><td colspan="5" class="small">Bowling card appears after the first ball.</td></tr>';
  const ex=inn.extras||{wd:0,nb:0,b:0,lb:0}; const rr=inn.legal?(inn.runs/(inn.legal/6)).toFixed(2):'0.00';
  return `<div class="live-score-mini ftp-no-bars"><table class="ftp-scorecard"><thead><tr><th colspan="2">${esc(inn.batTeam)}</th><th class="n">R</th><th class="n">B</th><th class="n">4s</th><th class="n">6s</th><th class="n">SR</th></tr></thead><tbody>${bat}</tbody><tfoot><tr><th>Extras</th><td>(b ${ex.b}, lb ${ex.lb}, w ${ex.wd}, nb ${ex.nb})</td><td class="n"><b>${ex.wd+ex.nb+ex.b+ex.lb}</b></td><td colspan="4"></td></tr><tr><th>Total</th><td>(${inn.wkts} wickets, ${Math.floor(inn.legal/6)}.${inn.legal%6} overs)</td><td class="n"><b>${inn.runs}</b></td><td colspan="4">RR: ${rr}</td></tr></tfoot></table><table class="ftp-bowling"><thead><tr><th>Bowling</th><th class="n">O</th><th class="n">R</th><th class="n">W</th><th class="n">Econ</th></tr></thead><tbody>${bowl}</tbody></table></div>`;
}
function foLiveScorecardPanel(){
  if(!M||!M.innings)return '';
  const inns=M.innings.filter(Boolean);
  return `<div class="panel"><h4>Live scorecard</h4><div class="pad">${inns.map(foTinyScorecardForInnings).join('<div style="height:8px"></div>')}</div></div>`;
}
function foWormMini(){
  if(!M||!M.worm)return '<div class="small">No worm data yet.</div>';
  const all=M.worm.filter(w=>w&&w.length); if(!all.length)return '<div class="small">No worm data yet.</div>';
  const mx=Math.max(10,...all.flatMap(w=>w.map(p=>p[1])))+10, mo=Math.max(50,...all.flatMap(w=>w.map(p=>p[0])));
  const xL=46,xR=536,yT=14,yB=176;                     // plot area (room for axis labels)
  const px=o=>(xL+o/mo*(xR-xL)), py=r=>(yB-r/mx*(yB-yT));
  let yaxis='';for(let i=0;i<=4;i++){const v=mx*i/4,y=py(v);yaxis+=`<line x1="${xL}" y1="${y.toFixed(1)}" x2="${xR}" y2="${y.toFixed(1)}" stroke="#eee"/><line x1="${xL-4}" y1="${y.toFixed(1)}" x2="${xL}" y2="${y.toFixed(1)}" stroke="#999"/><text x="${xL-7}" y="${(y+3).toFixed(1)}" font-size="9" fill="#666" text-anchor="end">${Math.round(v)}</text>`;}
  let xaxis='';for(let o=0;o<=mo;o+=10){const x=px(o);xaxis+=`<line x1="${x.toFixed(1)}" y1="${yB}" x2="${x.toFixed(1)}" y2="${yB+4}" stroke="#999"/><text x="${x.toFixed(1)}" y="${yB+15}" font-size="9" fill="#666" text-anchor="middle">${o}</text>`;}
  const axes=`<line x1="${xL}" y1="${yT}" x2="${xL}" y2="${yB}" stroke="#999"/><line x1="${xL}" y1="${yB}" x2="${xR}" y2="${yB}" stroke="#999"/>${yaxis}${xaxis}<text x="${(xL+xR)/2}" y="205" font-size="10" fill="#555" text-anchor="middle">Overs</text><text x="13" y="${(yT+yB)/2}" font-size="10" fill="#555" text-anchor="middle" transform="rotate(-90 13 ${(yT+yB)/2})">Total runs</text>`;
  const line=(w,col)=>`<polyline fill="none" stroke="${col}" stroke-width="2" points="${w.map(p=>(px(p[0]).toFixed(1))+','+(py(p[1]).toFixed(1))).join(' ')}"/>`+w.filter((p,i)=>i>0&&(p[2]||0)>(w[i-1][2]||0)).map(p=>`<circle cx="${px(p[0]).toFixed(1)}" cy="${py(p[1]).toFixed(1)}" r="3" fill="#a33328"/>`).join('');
  return `<svg viewBox="0 0 552 214" style="width:100%;max-width:640px;height:240px">${axes}${M.worm[0]?line(M.worm[0],'#2d6a8f'):''}${M.worm[1]?line(M.worm[1],'#c8a13a'):''}</svg><div class="small"><span style="color:#2d6a8f">■</span> ${esc(M.innings[0]?M.innings[0].batTeam:'1st innings')} &nbsp; <span style="color:#c8a13a">■</span> ${esc(M.innings[1]?M.innings[1].batTeam:'2nd innings')} &nbsp; ● wicket</div>`;
}
function foOrdersPanel(){
  const O=App.orders||{}; const bat=(O.batOrder||[]).slice(0,11).map((n,i)=>`<tr><td class="n">${i+1}</td><td>${esc(n)}</td></tr>`).join('');
  const overs=(O.compiled||[]).map((n,i)=>n?`<span class="phasechip" title="over ${i+1}: ${esc(n)}">${i+1}</span>`:'').join(' ');
  return `<table><tr><th colspan="2">Batting order</th></tr>${bat||'<tr><td colspan="2" class="small">No batting order saved.</td></tr>'}</table><div style="margin-top:8px"><b class="small">Bowling map</b><br>${overs||'<span class="small">No bowling map saved.</span>'}</div><div class="small" style="margin-top:6px"><a href="#/orders">Open full orders page</a></div>`;
}
function foRivalryPanel(){
  if(!M||!M.meta)return '<div class="small">No rivalry yet.</div>';
  const A=M.meta.home,B=M.meta.away; let a=0,b=0,t=0; const rows=[];
  for(const r of (App.results||[])){
    if(!((r.home===A&&r.away===B)||(r.home===B&&r.away===A)))continue;
    if(!r.result||!r.result.winner)t++; else if(r.result.winner===A)a++; else if(r.result.winner===B)b++;
    rows.push(`<tr><td>${esc(r.date)}</td><td>${esc(r.result.text)}</td><td><a href="#/scorecard?i=${r.ix}">scorecard</a></td></tr>`);
  }
  return `<div class="status-strip"><span>${esc(A)}: <b>${a}</b></span><span>${esc(B)}: <b>${b}</b></span><span>Ties: <b>${t}</b></span></div><table style="margin-top:8px"><tr><th>Date</th><th>Result</th><th></th></tr>${rows.slice(-8).reverse().join('')||'<tr><td colspan="3" class="small">First meeting in this save.</td></tr>'}</table>`;
}
function foPartnershipPanel(){
  if(!M)return ''; return M.innings.filter(Boolean).map(inn=>`<div class="small"><b>${esc(inn.batTeam)}</b></div>${pshipBars(inn)||'<span class="small">No partnerships yet.</span>'}`).join('<div style="height:8px"></div>');
}
function foMatchLinks(){
  const tabs=['Details','Orders','Scorecard','Match Ratings','Commentary','Worm','Partnerships','Rivalry'];
  UI.matchTab=UI.matchTab||'Scorecard';
  return `<div class="ftp-match-links"><h4>Links</h4>${tabs.map(t=>`<a class="${UI.matchTab===t?'on':''}" onclick="UI.matchTab='${t}';renderMatch()">${t}</a>`).join('')}</div>`;
}
function foMatchPanel(){
  if(!M)return '';
  const tab=UI.matchTab||'Scorecard'; let body='';
  if(tab==='Details')body=`<table class="kv"><tr><td>Ground</td><td>${esc(M.meta.ground)}</td></tr><tr><td>Pitch</td><td>${esc(M.pitch)}</td></tr><tr><td>Weather</td><td>${esc(M.meta.weather||'')}</td></tr><tr><td>Toss</td><td>${esc(App.tossState&&App.tossState.txt||'-')}</td></tr></table>`;
  else if(tab==='Orders')body=foOrdersPanel();
  else if(tab==='Scorecard')body=foLiveScorecardPanel();
  else if(tab==='Match Ratings')body=(M.done&&M.result)?ratingsTable({home:M.meta.home,away:M.meta.away,innings:M.innings,result:M.result}):'<div class="small">Full ratings are finalised when the match ends. Current partial view:</div>'+ratingsTable({home:M.meta.home,away:M.meta.away,innings:M.innings,result:M.result||{}});
  else if(tab==='Commentary')body=`<div class="commfeed commbig">${foCommentRows(M.log,UI.commFilter||'all',140)}</div>`;
  else if(tab==='Worm')body=foWormMini();
  else if(tab==='Partnerships')body=foPartnershipPanel();
  else if(tab==='Rivalry')body=foRivalryPanel();
  return `<div class="match-subpanel"><div class="panel"><h4>${esc(tab)}</h4><div class="pad">${body}</div></div></div>`;
}

const foRenderMatchBase=renderMatch;
renderMatch=function(){
  foRenderMatchBase();
  foUpdateLiveTopbar();
  // scoped to the CURRENT render root (the smooth-render staging div during a
  // staged render). The old document-wide guard read the LIVE page's shell
  // state, so whether this built its shell alternated ball to ball - and the
  // later fo55 rebuild destroyed mc-main whenever it had (the page-height
  // bounce that read as a hard refresh every delivery).
  const rootRM=document.getElementById('page');
  if(!M||!M.innings||!M.innings[M.inns]||!rootRM||!rootRM.querySelector('.mc-main'))return;
  const main=rootRM.querySelector('.mc-main');
  if(main&&!rootRM.querySelector('.ftp-match-shell')){
    const shell=document.createElement('div'); shell.className='ftp-match-shell';
    const body=document.createElement('div'); body.className='ftp-match-body';
    main.parentNode.insertBefore(shell,main); shell.appendChild(document.createRange().createContextualFragment(foMatchLinks())); shell.appendChild(body); body.appendChild(main);
  }
  rootRM.querySelectorAll('.mc-cards b').forEach(b=>{const fp=findPlayer(b.textContent.trim());if(fp){b.title=playerTip(fp.p);b.classList.add('player-hoverable')}});
  const ctrl=rootRM.querySelector('.mc-controls');
  if(ctrl&&!ctrl.querySelector('.comm-filter'))ctrl.insertAdjacentHTML('beforeend',foFilterSelect('live'));
  const feed=rootRM.querySelector('.mc-comm .commfeed');
  if(feed)feed.innerHTML=foCommentRows(M.log,UI.commFilter||'all',90);
  const commPanel=rootRM.querySelector('.mc-comm .panel');
  if(commPanel&&!rootRM.querySelector('.match-subpanel'))commPanel.insertAdjacentHTML('afterend',foMatchPanel());
};

pgCommentary=function(q){
  const r=App.results[+(q.i??-1)];
  if(!r||!r.log){document.getElementById('page').innerHTML=crumb('Commentary')+'<div class="panel"><div class="pad">Pick a match from <a href="#/reports">Reports</a>.</div></div>';return}
  const byInn=[[],[]]; for(const L of r.log)byInn[L.inn||0].push(L);
  const filt=App._savedCommFilter||'all';
  const render=(arr,nm)=>`<div class="panel"><h4>${esc(nm)} innings - ball by ball</h4><div class="pad"><div class="ctlrow">${foFilterSelect('saved')}</div><div class="commfeed" style="max-height:520px">${foCommentRows(arr.slice().reverse(),filt,9999)}</div></div></div>`;
  document.getElementById('page').innerHTML=crumb(r.home+' v '+r.away,'Commentary')+
   `<div class="navsub"><b>${esc(r.result.text)}</b> · <a href="#/scorecard?i=${r.ix}">scorecard</a> · <a href="#/reports?i=${r.ix}">report</a></div>`+
   render(byInn[0],r.innings[0]?r.innings[0].batTeam:'1st')+(r.innings[1]?render(byInn[1],r.innings[1].batTeam):'');
};

const foScorecardBase=pgScorecard;
pgScorecard=function(q){
  foScorecardBase(q||{});
  foUpdateLiveTopbar();
  const page=document.getElementById('page'); if(!page)return;
  page.innerHTML=page.innerHTML.replace(/\bYou won the toss/g,(M&&M.user?esc(M.user.name):esc(userTeam().name))+' won the toss').replace(/\(you\)/gi,'');
  if(q&&q.view){
    let panel='';
    if(q.view==='worm')panel=`<div class="panel"><h4>Worm</h4><div class="pad">${foWormMini()}</div></div>`;
    if(q.view==='ratings')panel=`<div class="panel"><h4>Match ratings</h4><div class="pad">${M?ratingsTable({home:M.meta.home,away:M.meta.away,innings:M.innings,result:M.result||{}}):'<span class="small">Open a live match for live ratings.</span>'}</div></div>`;
    if(panel)page.insertAdjacentHTML('beforeend',panel);
  }
};

completeRound=function(){
  seasonInit(); const S=App.season; if(!S)return;
  if(S.round>=S.schedule.length){pgMatches();return}
  const roundNo=S.round; const rd=S.schedule[roundNo]||[];
  const oldPending=App.pending, oldM=M, oldToss=App.tossState;
  const roundDate=(()=>{const d=new Date(2026,6,4);d.setDate(d.getDate()+7*roundNo);return d.toLocaleDateString('en-GB',{weekday:'short',day:'numeric',month:'short',year:'numeric'})})();
  for(let i=0;i<rd.length;i++){
    const f=rd[i]; const key=fixtureKey(roundNo,f); if(S.played[key]!==undefined)continue;
    const home=GD.teams[f[0]], away=GD.teams[f[1]]; const isUser=(f[0]===App.teamIx||f[1]===App.teamIx);
    simBackground(f[0],f[1],{home:home.name,away:away.name,ground:home.ground,pitch:groundPitch(home.ground),weather:WXLIST[(roundNo*7+f[0]*3)%WXLIST.length],seed:5000+roundNo*10+f[0],date:roundDate,comp:'league',round:roundNo,isUser});
  }
  M=null; App.tossState=null; App.pending=null;
  econInit(); const me=userTeam();
  ledger('Ground maintenance',-me.seats);
  ledger('Academies (Y'+me.acadY+'/S'+me.acadS+')',-(me.acadY+me.acadS)*2500);
  const myLg=App.results.filter(r=>r.comp==='league'&&r.round===roundNo&&(r.home===me.name||r.away===me.name));
  for(const r of myLg){if(r.home===me.name){const att=attendance(me);ledger('Gate receipts ('+att.toLocaleString()+' att.)',att*9)} const won=r.result.winner===me.name; me.mood=Math.max(0,Math.min(6,me.mood+(won?1:-1))); me.supporters=Math.max(800,Math.round(me.supporters*(won?1.03:0.985)));}
  for(const tt of GD.teams)if(tt!==me)tt.bank+=45000-24*tt.seats/9;
  resolveMarket(); cupTick(); applyTraining();
  S.round=roundNo+1; App.round=S.round+1;
  mpInit(); for(const k in App.mp.packets)if(App.mp.packets[k].round<S.round)delete App.mp.packets[k];
  const digest=App.results.filter(r=>r.comp==='league'&&r.round===roundNo).map(r=>`<div class="bl">${esc(r.result.text)} <span class="small">(${esc(r.home)} v ${esc(r.away)})</span></div>`).join('');
  App._digest=`<div class="panel" style="border-left:4px solid #2d6a8f"><h4>Round ${roundNo+1} digest</h4><div class="pad">${digest}<div class="small" style="margin-top:3px">Round advanced to ${S.round+1}${S.round>=S.schedule.length?' (season complete)':''}. Training applied.</div></div></div>`;
  saveGame(false); location.hash='#/matches'; pgMatches(); foUpdateLiveTopbar();
};

// boot
(function(){
  if(loadGame()){location.hash=location.hash||'#/club';return}
  const saved=store('fo_club');
  if(saved!==null&&saved!==undefined&&GD.teams[+saved])App.teamIx=+saved;
  if(!store('fo_welcomed'))location.hash='#/welcome';
})();
route();


